##### Banner Snapshot
```rust
use fastapi_output::prelude::*;
use fastapi_output::testing::strip_ansi_codes;
use insta::assert_snapshot;

#[test]
fn test_banner_plain_snapshot() {
    let banner = Banner::new(OutputMode::Plain);
    let info = ServerInfo::new("1.0.0", "localhost", 8000)
        .docs_path("/docs")
        .redoc_path("/redoc")
        .openapi_path("/openapi.json");

    let output = banner.render(&info);
    assert_snapshot!("banner_plain", output);
}

#[test]
fn test_banner_rich_snapshot() {
    let banner = Banner::new(OutputMode::Rich);
    let info = ServerInfo::new("1.0.0", "localhost", 8000)
        .docs_path("/docs");

    let output = banner.render(&info);
    // Strip ANSI for readable snapshot
    let normalized = strip_ansi_codes(&output);
    assert_snapshot!("banner_rich_content", normalized);
}
```

##### Routes Table Snapshot
```rust
#[test]
fn test_routes_table_snapshot() {
    let display = RouteDisplay::new(OutputMode::Plain);
    let routes = vec![
        RouteEntry::new(HttpMethod::Get, "/users", "list_users"),
        RouteEntry::new(HttpMethod::Post, "/users", "create_user"),
        RouteEntry::new(HttpMethod::Get, "/users/{id}", "get_user"),
        RouteEntry::new(HttpMethod::Delete, "/users/{id}", "delete_user"),
    ];

    let output = display.render(&routes);
    assert_snapshot!("routes_table_basic", output);
}
```

##### Error Display Snapshots
```rust
#[test]
fn test_validation_error_snapshot() {
    let formatter = ErrorFormatter::new(OutputMode::Plain);
    let errors = vec![
        ValidationErrorDetail::new(
            vec![LocItem::field("body"), LocItem::field("email")],
            "value is not a valid email address",
            "value_error.email",
        ),
        ValidationErrorDetail::new(
            vec![LocItem::field("body"), LocItem::field("age")],
            "ensure this value is greater than 0",
            "value_error.number.not_gt",
        ),
    ];

    let result = formatter.format_validation_errors(&errors);
    assert_snapshot!("validation_error_multi", result.plain);
}

#[test]
fn test_http_error_snapshots() {
    let formatter = ErrorFormatter::new(OutputMode::Plain);

    let err_404 = HttpErrorInfo::new(404, "User not found")
        .path("/api/users/999")
        .method("GET");
    assert_snapshot!("http_error_404", formatter.format_http_error(&err_404).plain);

    let err_500 = HttpErrorInfo::new(500, "Database connection failed")
        .code("DB_ERROR")
        .path("/api/users")
        .method("POST");
    assert_snapshot!("http_error_500", formatter.format_http_error(&err_500).plain);
}
```

